"""
银山谷金山谷均线形态识别
检测创业板股票中的银山谷和金山谷信号
"""

import sys
import os
sys.path.insert(0, '/Users/tomato/Documents/potato/project/YFD')

import pandas as pd
import numpy as np
from datetime import datetime, timedelta
from YFD.data_reader import DataReader

def calculate_ma(prices, window):
    """计算移动平均线"""
    return prices.rolling(window=window, min_periods=window).mean()

def check_bullish_alignment(ma5, ma10, ma20):
    """检查多头排列: 5日 > 10日 > 20日"""
    return (ma5 > ma10) & (ma10 > ma20)

def check_spacing(ma5, ma20, threshold=0.08):
    """检查三线间距 < 8%"""
    spacing = (ma5 - ma20) / ma20
    return spacing < threshold

def detect_silver_valley(df, search_start_idx, search_end_idx):
    """
    检测银山谷（第一次多头排列信号）
    返回: (日期索引, 10日均线值) 或 (None, None)
    """
    for i in range(search_start_idx, search_end_idx):
        # 检查当日是否满足多头排列
        if not check_bullish_alignment(df.loc[i, 'MA5'], df.loc[i, 'MA10'], df.loc[i, 'MA20']):
            continue

        # 检查三线间距
        if not check_spacing(df.loc[i, 'MA5'], df.loc[i, 'MA20']):
            continue

        # 检查前一日是否不满足多头排列（首次形成）
        if i > 0:
            prev_bullish = check_bullish_alignment(
                df.loc[i-1, 'MA5'], 
                df.loc[i-1, 'MA10'], 
                df.loc[i-1, 'MA20']
            )
            if prev_bullish:
                continue

        # 找到银山谷
        return i, df.loc[i, 'MA20']

    return None, None

def detect_golden_valley(df, silver_idx, silver_ma10):
    """
    检测金山谷（第二次多头排列信号）

    条件:
    1. 距银山谷10-30个交易日
    2. 回调期间收盘价不跌破20日均线
    3. 再次形成多头排列
    4. 10日均线值高于银山谷时的10日均线值
    5. 三线间距 < 8%
    """
    # 搜索范围: 银山谷后10-30个交易日
    search_start = silver_idx + 10
    search_end = min(silver_idx + 31, len(df))

    if search_start >= len(df):
        return None, None

    # 检查回调期间是否跌破20日均线
    for i in range(silver_idx + 1, search_end):
        if df.loc[i, 'close'] < df.loc[i, 'MA20']:
            # 跌破20日均线，不符合条件
            return None, None

    # 在允许的范围内搜索金山谷
    for i in range(search_start, search_end):
        # 检查多头排列
        if not check_bullish_alignment(df.loc[i, 'MA5'], df.loc[i, 'MA10'], df.loc[i, 'MA20']):
            continue

        # 检查三线间距
        if not check_spacing(df.loc[i, 'MA5'], df.loc[i, 'MA20']):
            continue

        # 检查10日均线值是否高于银山谷
        if df.loc[i, 'MA10'] <= silver_ma10:
            continue

        # 检查前一日是否不满足多头排列（再次形成）
        if i > silver_idx:
            prev_bullish = check_bullish_alignment(
                df.loc[i-1, 'MA5'], 
                df.loc[i-1, 'MA10'], 
                df.loc[i-1, 'MA20']
            )
            if prev_bullish:
                continue

        # 找到金山谷
        return i, i - silver_idx

    return None, None

def main():
    # 初始化数据读取器
    reader = DataReader()

    # 截止日期
    end_date = datetime(2024, 7, 8)

    # 获取创业板股票列表
    stock_list = reader.get_stock_list(market='创业板')

    results = []

    print(f"开始检测创业板股票的银山谷和金山谷信号...")
    print(f"股票总数: {len(stock_list)}")

    for idx, stock_code in enumerate(stock_list, 1):
        if idx % 100 == 0:
            print(f"进度: {idx}/{len(stock_list)}")

        try:
            # 获取120个交易日的数据（用于计算均线和搜索）
            df = reader.get_daily_data(
                stock_code=stock_code,
                end_date=end_date,
                count=120
            )

            if df is None or len(df) < 60:
                continue

            # 重置索引为整数
            df = df.reset_index(drop=True)

            # 计算均线
            df['MA5'] = calculate_ma(df['close'], 5)
            df['MA10'] = calculate_ma(df['close'], 10)
            df['MA20'] = calculate_ma(df['close'], 20)

            # 删除均线计算不完整的行
            df = df.dropna(subset=['MA5', 'MA10', 'MA20'])
            df = df.reset_index(drop=True)

            if len(df) < 60:
                continue

            # 在最近60个交易日内搜索银山谷
            search_start_idx = max(0, len(df) - 60)
            search_end_idx = len(df)

            # 检测银山谷
            silver_idx, silver_ma10 = detect_silver_valley(df, search_start_idx, search_end_idx)

            if silver_idx is None:
                continue

            # 检测金山谷
            golden_idx, interval_days = detect_golden_valley(df, silver_idx, silver_ma10)

            if golden_idx is None:
                continue

            # 记录结果
            silver_date = df.loc[silver_idx, 'date'].strftime('%Y-%m-%d')
            golden_date = df.loc[golden_idx, 'date'].strftime('%Y-%m-%d')

            results.append({
                'code': stock_code,
                'silver_date': silver_date,
                'golden_date': golden_date,
                'interval': interval_days
            })

            print(f"找到: {stock_code}, 银山谷={silver_date}, 金山谷={golden_date}, 间隔={interval_days}天")

        except Exception as e:
            # 跳过出错的股票
            continue

    # 输出结果
    output_dir = '/Users/tomato/Documents/potato/project/YFD/yfd-agent-consensus/results/agent_consensus_batch/default_run/task_25_golden_valley/revised/openclaw'
    output_file = os.path.join(output_dir, 'golden_valley.txt')

    with open(output_file, 'w', encoding='utf-8') as f:
        if len(results) == 0:
            f.write("# 无符合条件的股票\n")
            print("\n未找到符合条件的股票")
        else:
            f.write("股票代码,银山谷日期,金山谷日期,间隔天数\n")
            for r in results:
                f.write(f"{r['code']},{r['silver_date']},{r['golden_date']},{r['interval']}\n")
            print(f"\n共找到 {len(results)} 只股票符合条件")
            print(f"结果已保存到: {output_file}")

if __name__ == '__main__':
    main()
