        # 检查多头排列
        if not check_bullish_alignment(df.loc[i, 'MA5'], df.loc[i, 'MA10'], df.loc[i, 'MA20']):
            continue

        # 检查三线间距
        if not check_spacing(df.loc[i, 'MA5'], df.loc[i, 'MA20']):
            continue

        # 检查10日均线值是否高于银山谷
        if df.loc[i, 'MA10'] <= silver_ma10:
            continue

        # 检查前一日是否不满足多头排列（再次形成）
        if i > silver_idx:
            prev_bullish = check_bullish_alignment(
