                df.loc[i-1, 'MA20']
            )
            if prev_bullish:
                continue

        # 找到金山谷
        return i, i - silver_idx

    return None, None

def main():
    print("开始检测创业板股票的银山谷和金山谷信号...")

    # 获取创业板股票列表
    print("获取创业板股票列表...")
